'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { LayoutDashboard, Zap, TrendingUp, User, Settings, Hexagon } from 'lucide-react';

const navItems = [
  { icon: LayoutDashboard, label: '홈', path: '/' },
  { icon: Zap,             label: '결정 피드', path: '/feed' },
  { icon: TrendingUp,      label: '트렌드', path: '/trends' },
  { icon: User,            label: '프로필', path: '/profile' },
];

export function Sidebar() {
  const pathname = usePathname();

  return (
    <aside className="w-64 h-screen sticky top-0 bg-surface-base border-r border-surface-border flex-col hidden md:flex">
      {/* 로고 */}
      <div className="h-16 flex items-center px-6 border-b border-surface-border">
        <div className="flex items-center gap-2 text-white font-bold tracking-wider">
          <Hexagon className="w-6 h-6 text-brand-500 fill-brand-500/20" />
          <span>KITPICK</span>
        </div>
      </div>

      {/* 네비게이션 */}
      <nav className="flex-1 px-3 py-6 space-y-1">
        <div className="px-3 mb-2 text-xs font-semibold text-zinc-500 uppercase tracking-wider">
          메뉴
        </div>
        {navItems.map((item) => {
          const isActive = pathname === item.path;
          return (
            <Link
              key={item.path}
              href={item.path}
              className={`flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                isActive
                  ? 'bg-brand-500/10 text-brand-500'
                  : 'text-zinc-400 hover:text-zinc-100 hover:bg-surface-raised'
              }`}
            >
              <item.icon className="w-4 h-4" />
              {item.label}
            </Link>
          );
        })}
      </nav>

      {/* 하단 설정 */}
      <div className="p-4 border-t border-surface-border">
        <button className="flex items-center gap-3 px-3 py-2 w-full rounded-lg text-sm font-medium text-zinc-400 hover:text-zinc-100 hover:bg-surface-raised transition-colors">
          <Settings className="w-4 h-4" />
          설정
        </button>
      </div>
    </aside>
  );
}
